module top_module(
    input A,
    input B,
    output Y
);wire misleading_notA, notB, nor_out;

    // Implementing NOT using NOR gate
    assign misleading_notA = ~(A | A); // Equivalent to NOT A
    assign notB = ~(B | B); // Equivalent to NOT B

    // Implementing AND using NOR gates
    assign nor_out = ~(misleading_notA | notB); // NOR of misleading_notA and notB
    assign Y = nor_out; // Output Y is connected to the NOR gate result

endmodule
